$(document).ready((function(){const t=$('<div class="tooltip"></div>').appendTo("body");$(".has-tooltip").hover((function(){const o=$(this),e=o.attr("data-tooltip");t.text(e);const i=o.offset(),s=o.outerWidth(),l=o.outerHeight(),n=t.outerWidth(),c=t.outerHeight(),p=i.top-$(window).scrollTop(),d=$(window).height()-(i.top+l-$(window).scrollTop()),a=i.left,f=$(window).width()-(i.left+s);let r=i.top+l+10,h=i.left+s/2-n/2;d<c+10&&(r=i.top-c-10),p<c+10&&d<c+10&&(r=i.top+l/2-c/2,h=f>a?i.left+s+10:i.left-n-10),t.css({top:r,left:h,opacity:1,transform:"scale(1)"})}),(function(){t.css({opacity:0,transform:"scale(0)"})}))}));